package sfc

import (
	"bytes"

	"github.com/ethereum/go-ethereum/common/hexutil"
	"github.com/ethereum/go-ethereum/log"
)

// GetPatch6ContractBin returns the Cycle-162 SFC bytecode re-flashed by the
// SfcV2Patch6 upgrade. It is distinct from the historical Patch4/Patch5
// accessors so each sealed testnet re-flash remains reproducible, while fresh
// SfcV2 activations consume this bytecode through GetLatestContractBin().
//
// Cycle-162 source: VinuChain/vinuchain-lists contracts/vinuchain/SFC.sol.
// Compiled with solc 0.5.17+commit.d19bba13 --optimize --optimize-runs=10000
// --evm-version=istanbul.
//
// Delta from Cycle-161 (v2.0.14-elemont, SfcV2Patch5): adds explicit recovery
// for legacy orphaned delegation entries where getStake[delegator][validator]
// is non-zero but stakePosition[delegator][validator] is zero. The bytecode:
//
//  1. adds registerStake(uint256) so an affected delegator can self-register
//     their orphaned pair into the stakes[] enumeration;
//  2. adds owner-only backfillStakes(address[],uint256[]) for bounded batch
//     remediation on testnet/mainnet;
//  3. makes _rawUndelegate tolerant of undelegate-to-zero for orphans by
//     skipping _removeStake(0) while preserving the sentinel guard for normal
//     registered entries.
//
// The contract version() value is 3.0.5. Validity of the compiled asset is
// enforced at opera binary startup via EnforcePatch6StartupCheck.
func GetPatch6ContractBin() []byte {
	return patch6ContractBin
}

// EnforcePatch6StartupCheck validates the compiled-in Patch6 bytecode at
// binary startup. A build whose Patch6 bytes are placeholder, all zero, too
// short, or byte-identical to Patch5 refuses to start rather than reaching the
// on-chain re-flash block with an invalid asset.
func EnforcePatch6StartupCheck() {
	if err := validatePatch6Bytecode(patch6ContractBin); err != nil {
		log.Crit("SfcV2Patch6 bytecode asset is invalid - the binary must not start with this build. Recompile SFC from vinuchain-lists and replace sfc_patch6_bytecode.go", "err", err)
	}
}

var patch6DeadbeefSentinel = []byte{0xde, 0xad, 0xbe, 0xef}

// patch6ContractBin is the deployed Cycle-162 runtime bytecode.
//
// Compiled 2026-05-16 from VinuChain/vinuchain-lists contracts/vinuchain/SFC.sol
// with solc 0.5.17+commit.d19bba13 --optimize --optimize-runs=10000
// --evm-version=istanbul.
// Size: 47,172 bytes. Hex-string sha256:
//
//	99a4403b4883d1bdf640b33a4532c6747c789e57c8df47e44b5aa51c1cdd9660
//
// Raw-bytes sha256:
//
//	31bd08725b430ebb832af070927fd900c4371dbbb6aab483e22abed9add6462b
var patch6ContractBin = hexutil.MustDecode("")

const minRealPatch6BytecodeLen = 10000

func validatePatch6Bytecode(code []byte) error {
	if len(code) == 0 {
		return errPatch6Empty
	}
	if len(code) < minRealPatch6BytecodeLen {
		return errPatch6TooShort
	}
	if len(code) >= len(patch6DeadbeefSentinel) && bytes.Equal(code[:len(patch6DeadbeefSentinel)], patch6DeadbeefSentinel) {
		return errPatch6Sentinel
	}
	allZero := true
	for _, b := range code {
		if b != 0 {
			allZero = false
			break
		}
	}
	if allZero {
		return errPatch6AllZero
	}
	if bytes.Equal(code, GetPatch5ContractBin()) {
		return errPatch6EqualsPatch5
	}
	return nil
}

type patch6Error string

func (e patch6Error) Error() string { return string(e) }

const (
	errPatch6Empty        patch6Error = "patch6 bytecode is empty"
	errPatch6TooShort     patch6Error = "patch6 bytecode shorter than minimum SFC size - placeholder not replaced"
	errPatch6Sentinel     patch6Error = "patch6 bytecode begins with deadbeef sentinel - placeholder not replaced"
	errPatch6AllZero      patch6Error = "patch6 bytecode is all zeros"
	errPatch6EqualsPatch5 patch6Error = "SfcV2Patch6 bytecode is byte-identical to Patch5 (Cycle-161) - the Patch6 re-flash would no-op on chain and the delegation backfill fix would not deploy"
)
